import{_ as i,o as e,c as n,a2 as t}from"./chunks/framework.DnrXFDHb.js";const r="/images/layar-baseline.png",l="/images/tombol-kalibrasi.png",o="/images/layar-kargo.png",s="/images/tombol-ai.png",d="/images/layar-koli.png",k="/images/tombol-hapus-koli.png",_=JSON.parse('{"title":"Screening X-Ray","description":"","frontmatter":{},"headers":[],"relativePath":"guide/screening.md","filePath":"guide/screening.md"}'),m={name:"guide/screening.md"};function g(u,a,p,h,c,b){return e(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="screening-x-ray" tabindex="-1">Screening X-Ray <a class="header-anchor" href="#screening-x-ray" aria-label="Permalink to &quot;Screening X-Ray&quot;">​</a></h1><p>Halaman ini adalah inti dari aplikasi — tempat operator melakukan pemeriksaan X-Ray terhadap kargo.</p><h2 id="persiapan-kamera" tabindex="-1">Persiapan Kamera <a class="header-anchor" href="#persiapan-kamera" aria-label="Permalink to &quot;Persiapan Kamera&quot;">​</a></h2><ol><li>Pastikan kamera/capture card terhubung ke komputer</li><li>Browser akan meminta izin akses kamera — klik <strong>Izinkan</strong></li><li>Dua panel video akan muncul: <ul><li><strong>Kamera Top View</strong> (kiri) — Kamera atas untuk deteksi koli</li><li><strong>Kamera Side View</strong> (kanan) — Kamera samping</li></ul></li><li>Gunakan dropdown di atas masing-masing panel untuk memilih perangkat kamera jika tersedia lebih dari satu</li></ol><h2 id="input-data-screening" tabindex="-1">Input Data Screening <a class="header-anchor" href="#input-data-screening" aria-label="Permalink to &quot;Input Data Screening&quot;">​</a></h2><p><strong>Cara 1 — Barcode Scanner:</strong></p><ol><li>Scan Barcode <strong>MAWB</strong> dan <strong>HAWB</strong>, dengan posisi cursor menyesuaikan isian.</li><li>Sistem akan otomatis mencocokkan dengan data cargo (jika ada) dan mengisi HAWB</li></ol><p><strong>Cara 2 — Scanner OCR :</strong></p><ul><li>Jika terintegrasi dengan kamera fixed/scanner, data MAWB/HAWB akan terisi otomatis</li><li>Status koneksi ditunjukkan oleh ikon <strong>WiFi</strong> (hijau = terhubung, merah = terputus)</li></ul><p><strong>Cara 3 — Link pada Data Cargo:</strong></p><ul><li>Masuk ke Halaman Data Cargo &gt; Pilih dokumen yang akan discan</li><li>Klik Link MAWB. Layar akan diteruskan ke layar Screening dengan MAWB &amp; HAWB terkait</li></ul><h2 id="ambil-foto-barang" tabindex="-1">Ambil Foto Barang <a class="header-anchor" href="#ambil-foto-barang" aria-label="Permalink to &quot;Ambil Foto Barang&quot;">​</a></h2><ol><li>Klik area <strong>Foto Barang</strong> (atau tombol Upload)</li><li>Pilih file gambar dari komputer</li><li>Preview akan muncul di panel Foto Barang</li></ol><h2 id="deteksi-koli-dengan-ai" tabindex="-1">Deteksi Koli dengan AI <a class="header-anchor" href="#deteksi-koli-dengan-ai" aria-label="Permalink to &quot;Deteksi Koli dengan AI&quot;">​</a></h2><p>Aplikasi mendukung tiga metode deteksi koli:</p><table tabindex="0"><thead><tr><th>Metode</th><th>Cara Kerja</th><th>Kelebihan</th></tr></thead><tbody><tr><td><strong>OpenCV</strong></td><td>Server-side Python (edge detection + contour finding)</td><td>Akurat, tidak membebani browser</td></tr><tr><td><strong>MediaPipe</strong></td><td>Client-side EfficientDet via WASM</td><td>Cepat, offline, tanpa server</td></tr><tr><td><strong>Manual</strong></td><td>Drag &amp; crop interaktif dengan mouse</td><td>Kontrol penuh oleh operator</td></tr></tbody></table><h2 id="kalibrasi-background-bgs" tabindex="-1">Kalibrasi Background (BGS) <a class="header-anchor" href="#kalibrasi-background-bgs" aria-label="Permalink to &quot;Kalibrasi Background (BGS)&quot;">​</a></h2><p>Proses Kalibrasi perlu dilakukan 1x saja saat instalasi XRay, yang berguna bagi AI untuk mengecualikan layar kosong, langkah-langkahnya adalah sbb:</p><ol><li>Pastikan tidak ada kargo di frame kamera (konveyor kosong) <img src="'+r+'" width="400"></li><li>Klik tombol <img src="'+l+'" width="150"></li><li>Sistem akan menyimpan baseline gambar (maksimal 2)</li><li>Baselines disimpan di localStorage browser</li></ol><p><strong>Langkah-langkah Deteksi dengan AI</strong></p><ol><li><p>Pastikan kamera Top View menampilkan kargo <img src="'+o+'" width="400"></p></li><li><p>Tekan tombol <img src="'+s+'" width="150">— sistem akan mendeteksi koli secara otomatis</p></li><li><p>Bounding box hijau akan muncul mengelilingi setiap koli yang terdeteksi</p></li><li><p>Hasil crop koli akan muncul di panel <strong>Hasil Crop Koli</strong></p></li><li><p>Jumlah koli terdeteksi otomatis mengisi field Qty</p></li></ol><h2 id="crop-manual" tabindex="-1">Crop Manual <a class="header-anchor" href="#crop-manual" aria-label="Permalink to &quot;Crop Manual&quot;">​</a></h2><p>Untuk mode <strong>Manual</strong>:</p><ol><li>Pilih metode <strong>Manual</strong> di Pengaturan</li><li>Klik dan drag pada video Top View atau Side View</li><li>Lepaskan mouse untuk menyimpan crop</li><li>Crop akan muncul di panel hasil</li></ol><h2 id="membuat-keputusan" tabindex="-1">Membuat Keputusan <a class="header-anchor" href="#membuat-keputusan" aria-label="Permalink to &quot;Membuat Keputusan&quot;">​</a></h2><p>Setelah data lengkap dan analisis selesai:</p><table tabindex="0"><thead><tr><th>Tombol</th><th>Arti</th></tr></thead><tbody><tr><td><strong>✔ Finished XRay</strong></td><td>Kargo dinyatakan <strong>LOLOS</strong> / release</td></tr><tr><td><strong>✖ Pending XRay</strong></td><td>Kargo dinyatakan <strong>DITOLAK</strong> / perlu pemeriksaan lanjutan</td></tr></tbody></table><p>Setelah memutuskan:</p><ol><li>Klik salah satu tombol keputusan</li><li>Data scan akan disimpan ke database</li><li>Gambar akan diberi watermark (MAWB, HAWB, timestamp)</li><li>Notifikasi sukses akan muncul</li></ol><h2 id="panel-hasil-crop" tabindex="-1">Panel Hasil Crop <a class="header-anchor" href="#panel-hasil-crop" aria-label="Permalink to &quot;Panel Hasil Crop&quot;">​</a></h2><img src="'+d+'" width="400"><p>Panel ini menampilkan semua hasil crop koli dari deteksi AI atau cropping manual. Setiap crop menampilkan:</p><ul><li>Gambar hasil crop</li><li>Nomor urut koli</li><li>Tombol <img src="'+k+'" width="50"> untuk menghapus crop tertentu</li></ul><h2 id="riwayat-scan-terbaru" tabindex="-1">Riwayat Scan Terbaru <a class="header-anchor" href="#riwayat-scan-terbaru" aria-label="Permalink to &quot;Riwayat Scan Terbaru&quot;">​</a></h2><p>Panel kanan bawah menampilkan 10 scan terakhir untuk referensi cepat operator.</p>',35)])])}const f=i(m,[["render",g]]);export{_ as __pageData,f as default};
